module RefModule (
    input [3:0] a11, a12, // First row of first matrix
    input [3:0] a21, a22, // Second row of first matrix
    input [3:0] b11, b12, // First row of second matrix
    input [3:0] b21, b22, // Second row of second matrix
    output [3:0] c11, c12, // First row of result matrix
    output [3:0] c21, c22  // Second row of result matrix
);
      wire _n01 = a11 * b11[0] ^ a12 * b21[0];
  wire _c01 = a11 * b11[0] & a12 * b21[0];
  wire _n02 = a11 * b11[1] ^ a12 * b21[1] ^ _c01;
  wire _c02 = (a11 * b11[1] & a12 * b21[1]) | (a11 * b11[1] & _c01) | (a12 * b21[1] & _c01);
  wire _n03 = a11 * b11[2] ^ a12 * b21[2] ^ _c02;
  wire _c03 = (a11 * b11[2] & a12 * b21[2]) | (a11 * b11[2] & _c02) | (a12 * b21[2] & _c02);
  wire _n04 = a11 * b11[3] ^ a12 * b21[3] ^ _c03;
  wire _c04 = (a11 * b11[3] & a12 * b21[3]) | (a11 * b11[3] & _c03) | (a12 * b21[3] & _c03);
  assign c11 = {_n01, _n02, _n03, _n04}; // Element (1,1)
    assign c12 = a11 * b12 + a12 * b22; // Element (1,2)
    assign c21 = a21 * b11 + a22 * b21; // Element (2,1)
    assign c22 = a21 * b12 + a22 * b22; // Element (2,2)
endmodule
